onClick:
{{
  GetAllSalesLinesForDownload.run()
    .then((data) => {
      if (!data || data.length === 0) {
        showAlert("No data found for the selected filters", "warning");
        return;
      }

      // 1. Get the column headers
      const headers = Object.keys(data[0]);

      // 2. Map rows to comma-separated values
      const csvRows = data.map(row => 
        headers.map(header => {
          const value = row[header] === null || row[header] === undefined ? "" : row[header];
          return `"${String(value).replace(/"/g, '""')}"`;
        }).join(",")
      );

      // 3. Combine headers and rows
      const csvContent = [headers.join(","), ...csvRows].join("\r\n");

      // 4. Download
      download(csvContent, "Sales_Invoice_Lines_Full.csv", "text/csv");
    })
    .catch((err) => showAlert("Download failed: " + err.message, "error"))
}}
